@startuml
participant "Alice" as A {
}
participant "Bob" as B {
}
A ->> B : message 1
B -->> A : ok
activate A
deactivate A
note right of A #red;line:red;text:green\n#green;bgcolor:#0f8536;color:white\ntext-align:center;font-size:24px;\nfont-family:"Comic Sans MS"\n<-->\n</b><i>Alice's note here.</i></u>: This is Alice's first interaction.\nnote left of B #blue;line:dashed;text:black\nbgcolor:pink:text-align:right;font-style:bold\n<b>Note for Bob:</b>\n<u>This could be important!</u>: Important info from Bob side.
A --> B : message 2
B <-- A : ok
@enduml
